// mamba2_ssd_scan.cu — custom GPU kernel for the Mamba-2 (SSD) selective-scan step.
//
// WHY: Codestral Mamba (mamba-codestral-7B, 7B) decodes with the SSD recurrence on
// the CPU (`mamba2_ssd_step`) — the bottleneck, exactly as the Mamba-1 S6 scan was
// for falcon (see mamba_scan.cu). Per layer the scan is num_heads·head_dim·d_state =
// 128·64·128 = 1.05 M fused multiply-adds, each gated by a per-head exp → the whole
// per-token cost. This kernel moves that loop to the GPU with IDENTICAL numerics.
//
// This is the grouped multi-head cousin of `mamba1_s6_scan`. Differences vs S6:
//   • A is SCALAR PER HEAD (a_log[num_heads]), not a per-channel [d_inner·d_state]
//     matrix → one exp per THREAD (not per state element): Abar = exp(-dt·exp(a_log)).
//   • dt is PER HEAD (dt[num_heads]) and arrives ALREADY = softplus(dt_in + dt_bias),
//     computed on the host (cheap, shape-preserving) — kernel is arch-agnostic.
//   • B and C are GROUPED: B[g,·], C[g,·] with g = head / (num_heads/n_groups). All
//     n_groups·d_state of B and C are staged in shared memory; each thread indexes its
//     head's group slice.
//   • D-skip is per head (d_skip[num_heads]).
// The learnable gated RMSNorm over d_inner (HF MambaRMSNormGated, gate-first) is
// applied on the HOST after this kernel (cheap, needs z + norm_w), so the kernel emits
// the raw scan output y exactly like the S6 kernel.
//
// Recurrence (per layer), matching mamba2_ssd_step EXACTLY. For channel c (head
// hh = c/head_dim, position p = c%head_dim, group g = hh/(num_heads/n_groups)):
//   Abar    = exp(-dt[hh] * exp(a_log[hh]))                 (scalar per head, in (0,1])
//   h[c,n]  = h[c,n] * Abar + dt[hh] * B[g,n] * x[c]
//   y[c]    = D[hh] * x[c] + Σ_n C[g,n] * h[c,n]
//
// NUMERICS: fp32, PRECISE expf (matches CPU f32::exp within the 1e-4 gate). Accumulation
// order left-associative, n=0..d_state — byte-identical to the CPU loop.
//
// THREAD MAPPING: ONE THREAD PER CHANNEL c (d_inner threads), same as S6. Each thread
// owns its d_state states resident in VRAM across tokens, sweeps n, accumulates y[c]
// locally. Build: build.rs nvcc --cubin; loaded via the cudarc driver. Gated by
// MESH_GPU_SCAN=1.
//
// H MEMORY LAYOUT (coalescing): the resident state `h` is STATE-MAJOR —
// h[n * d_inner + c]. At a fixed n, consecutive threads (channels c, c+1) hit
// consecutive addresses, so each warp's 32 h reads/writes fold into ONE 128B
// coalesced transaction (vs the old channel-major c*d_state+n layout, whose 512B
// per-thread stride made every h access a separate cache line ≈ 32× effective-
// bandwidth waste — the measured ~108ms ssd_step wall, see MAMBA2_VGPU_FUSED_LAYER.md
// S3). This is a GPU-INTERNAL layout: the Rust caller transposes the channel-major
// host state on seed and (only under MESH_GPU_SCAN_MIRROR_HOST) back on mirror, so
// the CPU reference is untouched. Per-thread accumulation stays fully sequential
// (left-assoc n=0..d_state) → output BIT-IDENTICAL to the CPU scan; only the h
// addresses changed, not the arithmetic or its order.

extern "C" __global__ void mamba2_ssd_scan(
    const float* __restrict__ x_conv, // [d_inner] conv output (the "x")
    const float* __restrict__ dt,     // [num_heads] softplus(dt_in + dt_bias), host-computed
    const float* __restrict__ b_vec,  // [n_groups * d_state] grouped B
    const float* __restrict__ c_vec,  // [n_groups * d_state] grouped C
    const float* __restrict__ a_log,  // [num_heads] scalar log-A per head
    const float* __restrict__ d_skip, // [num_heads] D skip per head
    float* __restrict__ h,            // [d_inner * d_state] recurrent state (in/out)
    float* __restrict__ y,            // [d_inner] output
    int d_inner,
    int d_state,
    int num_heads,
    int n_groups)
    // NOTE: head_dim is NOT a parameter — it is derived as d_inner/num_heads. This keeps
    // the launch at 8 ptrs + 4 ints = 12 args, cudarc's max LaunchAsync tuple arity.
{
    // Stage grouped B and C in shared memory: [0..bc_len) = B, [bc_len..2*bc_len) = C,
    // where bc_len = n_groups * d_state. Every channel of a head reads the same group
    // slice, so one cooperative load per block kills the redundant global traffic.
    extern __shared__ float bc[];
    const int bc_len = n_groups * d_state;
    for (int i = threadIdx.x; i < bc_len; i += blockDim.x) {
        bc[i]          = b_vec[i];
        bc[bc_len + i] = c_vec[i];
    }
    __syncthreads();

    const int c = blockIdx.x * blockDim.x + threadIdx.x;
    if (c >= d_inner) return;

    const int head_dim = d_inner / num_heads; // derived (not a kernel arg — arity cap)
    const int hh = c / head_dim;
    const int heads_per_group = num_heads / n_groups;
    const int g = hh / heads_per_group;
    const float* __restrict__ bs = bc + g * d_state;          // this head's group B
    const float* __restrict__ cs = bc + bc_len + g * d_state; // this head's group C

    const float dt_h = dt[hh];
    const float x_c  = x_conv[c];
    // Abar = exp(-dt * exp(a_log)) — SCALAR per head, computed ONCE per thread (vs the
    // S6 per-state exp). PRECISE expf to match the CPU f32::exp reference.
    const float abar = expf(-dt_h * expf(a_log[hh]));
    // yi = D[hh] * x[c]  (D-skip, added BEFORE the state sum — matches the CPU init).
    float yi = d_skip[hh] * x_c;

    // Coalesced STATE-MAJOR sweep: idx = n*d_inner + c. Consecutive threads at the
    // same n are 4B apart → one coalesced transaction per warp per n (vs 512B stride
    // in the old c*d_state+n layout). Accumulation over n is still sequential per
    // thread (left-assoc) → bit-identical to the CPU reference; only h's address map
    // changed. `d_inner` is the state-major row stride.
    #pragma unroll 4
    for (int n = 0; n < d_state; ++n) {
        const int idx = n * d_inner + c;
        // h = h*Abar + (dt*B)*x  — left-assoc, identical to the CPU kernel.
        const float hv = h[idx] * abar + dt_h * bs[n] * x_c;
        h[idx] = hv;
        yi += cs[n] * hv;
    }
    y[c] = yi;
}
